function square(n) {
    return n * n;
}
console.log(square(7));

const nums = [1, 2, 3, 4, 5];
const evens = nums.filter(n => n % 2 === 0);
console.log(evens);

const nums = [1, 2, 3, 4, 5];
const doubled = nums.map(n => n * 2);
console.log(doubled);

const arr = [10, 20, 30];
const [a, b] = arr;
console.log(a, b);
const newArr = [...arr, 40, 50];
console.log(newArr);

function fetchData() {
    return new Promise(resolve => setTimeout(() => resolve('Data loaded!'), 100));
}
async function main() {
    const data = await fetchData();
    console.log(data);
}
main();
